import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.C_Knpfj2.js";const m=JSON.parse('{"title":"Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"reference/compatibility.md","filePath":"reference/compatibility.md","lastUpdated":1781721505000}'),r={name:"reference/compatibility.md"};function c(s,e,n,d,l,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h1><p>AOSC has two version axes:</p><ul><li><strong>AOSC version</strong>: the plugin release version, such as <code>0.1.0</code>.</li><li><strong>OpenSearch line</strong>: the OpenSearch major line the artifact targets, such as <code>os2</code>.</li></ul><p>Release artifacts are built per supported OpenSearch minor because OpenSearch plugins are loaded with version compatibility checks. Documentation is versioned by exact AOSC patch version plus OpenSearch major line, for example <code>/0.1.0-os2/</code>.</p><h2 id="current-opensearch-2-x-line" tabindex="-1">Current OpenSearch 2.x Line <a class="header-anchor" href="#current-opensearch-2-x-line" aria-label="Permalink to &quot;Current OpenSearch 2.x Line&quot;">​</a></h2><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Release branch</td><td><code>releases/2.x</code></td></tr><tr><td>AOSC version</td><td><code>0.1.0</code></td></tr><tr><td>Documentation version</td><td><code>0.1.0-os2</code></td></tr><tr><td>Primary OpenSearch version</td><td><code>2.19.0</code></td></tr><tr><td>Release ZIP minors</td><td><code>2.15</code>, <code>2.17</code>, <code>2.19</code></td></tr><tr><td>CI test versions</td><td><code>2.15.0</code>, <code>2.17.0</code>, <code>2.17.1</code>, <code>2.19.0</code>, <code>2.19.3</code></td></tr></tbody></table></div><p>The ZIP name includes the OpenSearch minor it was built for:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensearch-aosc-0.1.0-opensearch-2.19.zip</span></span></code></pre></div><p>Use the ZIP matching your OpenSearch minor. A <code>2.19</code> ZIP is intended for the <code>2.19.x</code> patch line unless a release note says otherwise.</p><h2 id="compatibility-policy" tabindex="-1">Compatibility Policy <a class="header-anchor" href="#compatibility-policy" aria-label="Permalink to &quot;Compatibility Policy&quot;">​</a></h2><p>Patch-level compatibility is validated by CI for the exact OpenSearch versions listed above. Other patch releases in the same OpenSearch minor may work because the plugin descriptor uses a patch-compatible semver range, but test the exact OpenSearch version before production use.</p><p>Do not install an AOSC ZIP built for a different OpenSearch minor unless the release notes explicitly say it is supported.</p>',12)])])}const u=t(r,[["render",c]]);export{m as __pageData,u as default};
